public enum ConnectedFfiError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {

    
    
    case InitializationError(msg: String
    )
    case DiscoveryError(msg: String
    )
    case ConnectionError(msg: String
    )
    case NotInitialized
    case InvalidArgument(msg: String
    )
    case Internal(msg: String
    )

    

    

    
    public var errorDescription: String? {
        String(reflecting: self)
    }
    
}

#if compiler(>=6)
extension ConnectedFfiError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeConnectedFfiError: FfiConverterRustBuffer {
    typealias SwiftType = ConnectedFfiError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ConnectedFfiError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .InitializationError(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 2: return .DiscoveryError(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 3: return .ConnectionError(
            msg: try FfiConverterString.read(from: &buf)
            )
        case 4: return .NotInitialized
        case 5: return .InvalidArgument(
            msg: try FfiConverterString.read(from: &buf)
